      { "id": "ff7rebirth_materia_completionist", "name": "Materia Completionist", "type": "Prata", "description": "Develop all possible materia together with Chadley.", "tip": "Exige todos os 169 World Intel e desenvolver todas as materias disponiveis no Chadley, incluindo copias.", "is_missable": false, "is_spoiler": false },
      { "id": "ff7rebirth_7th_assemble", "name": "7th, Assemble!", "type": "Bronze", "description": "Recruit all Midgar 7th Infantry units for the parade in Junon.", "tip": "Encontre todas as unidades no Capitulo 4. Chapter select permite repetir.", "is_missable": false, "is_spoiler": false },
      { "id": "ff7rebirth_stealing_the_show", "name": "Stealing the Show", "type": "Bronze", "description": "Win the prize for outstanding performance in the Junon parade.", "tip": "Monte a parada com todas as unidades e execute bem o minigame.", "is_missable": false, "is_spoiler": false },
      { "id": "ff7rebirth_card_royalty", "name": "Card Royalty", "type": "Bronze", "description": "Win the Queen's Blood tournament held on board the Shinra-8.", "tip": "Venca o torneio de Queen's Blood. Guarde saves entre rodadas se quiser reduzir retrabalho.", "is_missable": false, "is_spoiler": false },
      { "id": "ff7rebirth_critically_acclaimed", "name": "Critically Acclaimed", "type": "Bronze", "description": "Receive a review of S or higher for your performance in Loveless at the Gold Saucer.", "tip": "Minigame de Loveless no Capitulo 12; a rota pode variar por affinity. Use save manual ou chapter select.", "is_missable": false, "is_spoiler": true },
      { "id": "ff7rebirth_1_star_startup", "name": "1-Star Startup", "type": "Bronze", "description": "Donate 10 items to the treasure trove at Johnny's Seaside Inn.", "tip": "Primeiro marco de Johnny's Treasure Trove.", "is_missable": false, "is_spoiler": false },
      { "id": "ff7rebirth_3_star_hotel", "name": "3-Star Hotel", "type": "Bronze", "description": "Donate 30 items to the treasure trove at Johnny's Seaside Inn.", "tip": "Continue coletando Collector Items por side content e minigames.", "is_missable": false, "is_spoiler": false },
      { "id": "ff7rebirth_5_star_hotel", "name": "5-Star Hotel", "type": "Prata", "description": "Donate 60 items to the treasure trove at Johnny's Seaside Inn.", "tip": "Marco avancado do Treasure Trove; exige bastante side content e minigames.", "is_missable": false, "is_spoiler": false },
      { "id": "ff7rebirth_7_star_hotel", "name": "7-Star Hotel", "type": "Ouro", "description": "Inform Johnny that you have donated all possible items to his treasure trove.", "tip": "O grande requisito de quase 100%: side quests, World Intel, minigames, combat simulator, Brutal/Legendary bouts e itens do Johnny.", "is_missable": false, "is_spoiler": false },
      { "id": "ff7rebirth_polygonal_prizefighter", "name": "Polygonal Prizefighter", "type": "Bronze", "description": "Defeat Sephiroth in 3D Brawler.", "tip": "Minigame avancado de 3D Brawler; exige reconhecer padroes e desbloqueios tardios.", "is_missable": false, "is_spoiler": true },
      { "id": "ff7rebirth_piano_virtuoso", "name": "Piano Virtuoso", "type": "Bronze", "description": "Play all six Piano Outreach Association songs well enough to receive remuneration.", "tip": "Toque as seis musicas de piano com rank suficiente. A platina nao exige S-rank nelas, mas exige consistencia.", "is_missable": false, "is_spoiler": false },
      { "id": "ff7rebirth_are_you_not_entertained", "name": "Are You Not Entertained?", "type": "Bronze", "description": "Complete all bouts in the Musclehead Colosseum.", "tip": "Complete todos os bouts do Musclehead Colosseum; alguns abrem so depois da historia.", "is_missable": false, "is_spoiler": false },
      { "id": "ff7rebirth_hall_of_famer", "name": "Hall of Famer", "type": "Bronze", "description": "Win all chocobo races.", "tip": "Venca todas as corridas de chocobo, incluindo o Gold Cup desbloqueado por side quest.", "is_missable": false, "is_spoiler": false },
      { "id": "ff7rebirth_my_job_here_is_done", "name": "My Job Here Is Done", "type": "Bronze", "description": "Complete all quests.", "tip": "Complete as 36 side quests. Chapter select permite retornar ao Capitulo 13 para cleanup.", "is_missable": false, "is_spoiler": false },
      { "id": "ff7rebirth_grind_it_out", "name": "Grind It Out", "type": "Bronze", "description": "Attain level 70 with a character.", "tip": "Normalmente vem durante cleanup, Hard Mode, colosseum e combat simulator.", "is_missable": false, "is_spoiler": false },
      { "id": "ff7rebirth_staggering_success", "name": "Staggering Success", "type": "Bronze", "description": "Deal 300% or more damage to a staggered enemy.", "tip": "Use Tifa e habilidades que aumentam multiplicador de stagger em uma janela longa.", "is_missable": false, "is_spoiler": false },
      { "id": "ff7rebirth_well_rounded", "name": "Well-Rounded", "type": "Bronze", "description": "Master all weapon abilities and limit breaks, including those found in folios.", "tip": "Domine todas as habilidades de armas e limite/folios. Isso tambem prepara builds para Hard Mode.", "is_missable": false, "is_spoiler": false },
      { "id": "ff7rebirth_of_hardy_stock", "name": "Of Hardy Stock", "type": "Prata", "description": "Complete all chapters on Hard difficulty.", "tip": "Hard Mode libera apos terminar a historia. Itens ficam bloqueados, benches nao restauram MP e builds importam muito.", "is_missable": false, "is_spoiler": false },
      { "id": "ff7rebirth_virtually_renowned", "name": "Virtually Renowned", "type": "Prata", "description": "Complete all of Chadley's combat simulations.", "tip": "Inclui Brutal/Legendary bouts, requisitos de World Intel, inimigos avaliados, Gilgamesh e lutas avancadas do Chadley.", "is_missable": false, "is_spoiler": true }
